import React from 'react';

const SweetoLogo = ({ size = 48, className = '' }) => {
  return (
    <svg 
      viewBox="0 0 100 100" 
      className={`select-none ${className}`} 
      style={{ width: size, height: size }}
      fill="none" 
      xmlns="http://www.w3.org/2000/svg"
    >
      <image 
        href="data:image/png;base64," 
        x="0" 
        y="0" 
        width="100" 
        height="100" 
      />
    </svg>
  );
};

export default SweetoLogo;
